// Prepare DataForSEO request for batch of keywords
const keywords = $input.all().map(item => item.json);

// Build tasks array for DataForSEO
const tasks = keywords.map((kw, index) => ({
  keyword: kw.keyword,
  location_code: 2840, // United States
  language_code: 'en',
  device: 'desktop',
  os: 'windows',
  tag: kw.id // Use keyword ID as tag for matching
}));

return [{
  json: {
    tasks,
    keywords
  }
}];

// Parse DataForSEO response and extract rankings
const response = $input.first().json;
const tasks = response.tasks || [];
const ourDomain = 'iaml.com'; // Update this

const today = new Date().toISOString().split('T')[0];
const rankings = [];

tasks.forEach(task => {
  if (task.status_code !== 20000) {
    console.log(`Task failed: ${task.status_message}`);
    return;
  }

  const result = task.result?.[0];
  if (!result) return;

  const keyword_id = task.data?.tag;
  const items = result.items || [];

  // Find our position
  let position = null;
  let ranking_url = null;
  let has_featured_snippet = false;
  let featured_snippet_owner = null;
  const competitor_positions = [];

  items.forEach((item, idx) => {
    // Check featured snippet
    if (item.type === 'featured_snippet') {
      has_featured_snippet = true;
      const domain = new URL(item.url || '').hostname.replace('www.', '');
      featured_snippet_owner = domain === ourDomain ? 'us' : domain;
    }

    // Check organic results
    if (item.type === 'organic' && item.domain) {
      const domain = item.domain.replace('www.', '');

      if (domain === ourDomain && position === null) {
        position = item.rank_absolute;
        ranking_url = item.url;
      } else if (competitor_positions.length < 5) {
        competitor_positions.push({
          domain: domain,
          position: item.rank_absolute
        });
      }
    }
  });

  rankings.push({
    keyword_id,
    collected_date: today,
    position,
    ranking_url,
    has_featured_snippet,
    featured_snippet_owner,
    competitor_positions: JSON.stringify(competitor_positions)
  });
});

return rankings.map(r => ({ json: r }));

// Continue to next batch or finish
const items = $input.all();
return [{
  json: {
    workflow_id: 'RNK-01',
    workflow_name: 'Web Intel - Rankings - Daily Tracker',
    status: 'success',
    records_processed: items.length,
    completed_at: new Date().toISOString()
  }
}];
